INSERT INTO directory_entries (name, category, description, address, city, province, phone, email, website, speaks_english, is_featured, is_verified, is_claimed, created_at, updated_at) VALUES

('Dr. De Boer / InternationalDoctor.eu', 'Healthcare', 'English-speaking family doctor providing compassionate, comprehensive, and culturally sensitive family medical care to expats and international residents in Madrid. Dr. Hanneke de Boer is fluent in English, Dutch, Spanish, and Swedish (C1+ level), bringing a deeply human, globally informed approach to medicine. Born in the Netherlands, raised in Sweden, and educated in Prague, she understands the challenges of seeking healthcare in a foreign country. Services include online consultations (45€), clinic consultations (80€), and home visits for those unable to come to the clinic. Provides personalized care and treatment plans using evidence-based medicine, with specializations in primary care, emergency medicine, lifestyle medicine, cardiovascular risk management, palliative care, and diagnostic ultrasound. Works with the Spanish electronic prescription system (REMPe), making prescriptions valid in all pharmacies in Spain. Completed residency in Family Medicine at Hospital Universitario Infanta Sofía in Madrid, alongside a Master''s in Emergencies, Urgencies, and Catastrophes from CEU-San Pablo. Private practice - patients can request reimbursement from their insurance.', 'Calle del Marqués de la Valdavia 95, local 3, 28100 Alcobendas', 'Alcobendas', 'Madrid', '+34 916 238 440', 'info@internationaldoctor.eu', 'https://www.internationaldoctor.eu/', true, true, true, false, NOW(), NOW());
